def is_isbn_10(input_string: str) -> bool:
    # Remove hyphens
    input_string = input_string.replace('-', '')

    if len(input_string) != 10:
        return False

    total_sum = 0
    for i in range(10):
        if input_string[i].isdigit():
            total_sum += int(input_string[i]) * (i + 1)
        elif input_string[i] == 'X' and i == 9:
            total_sum += 10
        else:
            return False

    return total_sum % 11 == 0

